import {
  Menu,
  PanelLeftClose,
  Copy,
  Check,
  ChevronUp,
  ChevronDown,
  Upload,
  Download,
  FileUp,
} from "lucide-react";
import { useEffect, useState, useCallback } from "react";
import { ConfirmDialog } from "./components/confirm-dialog";
import { ResizeHandle } from "./components/resize-handle";
import { SessionList, type ViewMode } from "./components/session-list";
import { SessionView } from "./components/session-view";
import { UploadDialog } from "./components/upload-dialog";
import type { PushResult, SessionSummary } from "./types";

type DialogState =
  | { kind: "hidden" }
  | { kind: "confirm" }
  | { kind: "pushing" }
  | { kind: "result"; result: PushResult };

export function App() {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [sessions, setSessions] = useState<SessionSummary[]>([]);
  const [projects, setProjects] = useState<string[]>([]);
  const [selectedSessionId, setSelectedSessionId] = useState<string | null>(
    null
  );
  const [copied, setCopied] = useState(false);
  const [page, setPage] = useState(0);
  const [loading, setLoading] = useState(false);
  const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());
  const [dialog, setDialog] = useState<DialogState>({ kind: "hidden" });
  const [showUploadDialog, setShowUploadDialog] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);
  const [viewMode, setViewMode] = useState<ViewMode>("time");
  const [sidebarWidth, setSidebarWidth] = useState(320);

  const MIN_SIDEBAR_WIDTH = 240;
  const MAX_SIDEBAR_WIDTH = 600;
  const SESSIONS_PER_PAGE = 100;

  const handleSidebarResize = useCallback((delta: number) => {
    setSidebarWidth((w) =>
      Math.min(MAX_SIDEBAR_WIDTH, Math.max(MIN_SIDEBAR_WIDTH, w + delta))
    );
  }, []);

  useEffect(() => {
    fetch("/api/projects")
      .then((r) => r.json())
      .then((data: string[]) => setProjects(data))
      .catch((err) => console.error("Failed to load projects:", err));
  }, []);

  useEffect(() => {
    setLoading(true);
    const params = new URLSearchParams();
    params.set("limit", String(SESSIONS_PER_PAGE));
    params.set("offset", String(page * SESSIONS_PER_PAGE));

    fetch(`/api/sessions?${params}`)
      .then((r) => r.json())
      .then((data: SessionSummary[]) => setSessions(data))
      .catch((err) => console.error("Failed to load sessions:", err))
      .finally(() => setLoading(false));
  }, [page, refreshKey]);

  const selectedSession = sessions.find(
    (s) => s.session_id === selectedSessionId
  );

  const handleCopyResume = () => {
    if (!selectedSessionId) return;
    navigator.clipboard.writeText(`claude --resume ${selectedSessionId}`);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleCollectClick = () => {
    if (checkedIds.size === 0) return;
    setDialog({ kind: "confirm" });
  };

  const handleDownloadClick = async () => {
    if (checkedIds.size === 0) return;
    try {
      const res = await fetch("/api/sessions/download", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ session_ids: [...checkedIds] }),
      });
      if (!res.ok) return;
      const blob = await res.blob();
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = "vibelens-export.zip";
      a.click();
      URL.revokeObjectURL(url);
    } catch (err) {
      console.error("Download failed:", err);
    }
  };

  const handlePushConfirm = useCallback(async () => {
    setDialog({ kind: "pushing" });
    try {
      const res = await fetch("/api/push/mongodb", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          session_ids: [...checkedIds],
          target: "mongodb",
        }),
      });
      if (!res.ok) {
        let errorMsg = `HTTP ${res.status}`;
        try {
          const body = await res.json();
          errorMsg = body.detail || JSON.stringify(body);
        } catch {
          errorMsg = await res.text().catch(() => errorMsg);
        }
        setDialog({
          kind: "result",
          result: {
            total: checkedIds.size,
            uploaded: 0,
            skipped: 0,
            errors: [{ session_id: "", error: errorMsg }],
          },
        });
        return;
      }
      const result: PushResult = await res.json();
      setDialog({ kind: "result", result });
    } catch (err) {
      setDialog({
        kind: "result",
        result: {
          total: checkedIds.size,
          uploaded: 0,
          skipped: 0,
          errors: [{ session_id: "", error: String(err) }],
        },
      });
    }
  }, [checkedIds]);

  const handleDialogClose = () => {
    if (dialog.kind === "result" && dialog.result.uploaded > 0) {
      setCheckedIds(new Set());
    }
    setDialog({ kind: "hidden" });
  };

  const renderDialog = () => {
    switch (dialog.kind) {
      case "confirm":
        return (
          <ConfirmDialog
            title="Send to MongoDB"
            message={`Send ${checkedIds.size} session${checkedIds.size !== 1 ? "s" : ""} to MongoDB?\n\nExisting sessions will be skipped automatically.`}
            confirmLabel="Send"
            onConfirm={handlePushConfirm}
            onCancel={handleDialogClose}
          />
        );
      case "pushing":
        return (
          <ConfirmDialog
            title="Sending..."
            message={`Uploading ${checkedIds.size} session${checkedIds.size !== 1 ? "s" : ""} to MongoDB...`}
            onConfirm={() => {}}
            onCancel={() => {}}
            loading
          />
        );
      case "result": {
        const r = dialog.result;
        const hasErrors = r.errors.length > 0;
        const lines = [
          `Uploaded: ${r.uploaded}`,
          `Skipped: ${r.skipped}`,
          `Total: ${r.total}`,
        ];
        if (hasErrors) {
          lines.push("");
          lines.push(`Errors: ${r.errors.length}`);
          for (const e of r.errors.slice(0, 3)) {
            lines.push(`  ${e.session_id || "—"}: ${e.error}`);
          }
        }
        return (
          <ConfirmDialog
            title={hasErrors ? "Completed with errors" : "Upload complete"}
            message={lines.join("\n")}
            confirmLabel="OK"
            cancelLabel="Close"
            onConfirm={handleDialogClose}
            onCancel={handleDialogClose}
          />
        );
      }
      default:
        return null;
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-zinc-950 text-zinc-100">
      {/* Sidebar */}
      {sidebarOpen && (
        <aside
          style={{ width: sidebarWidth }}
          className="relative border-r border-zinc-800 flex flex-col shrink-0 bg-zinc-900"
        >
          <ResizeHandle side="left" onResize={handleSidebarResize} />
          <div className="flex items-center justify-between px-4 h-[75px] border-b border-zinc-800 sticky top-0">
            <div className="flex items-center gap-3">
              <img src="/icon.png" alt="VibeLens" className="w-12 h-12" />
              <h1 className="text-2xl font-bold text-cyan-400">VibeLens</h1>
            </div>
            <button
              onClick={() => setSidebarOpen(false)}
              className="text-zinc-500 hover:text-zinc-300 transition"
              title="Collapse sidebar"
            >
              <PanelLeftClose className="w-4 h-4" />
            </button>
          </div>

          {/* Toolbar: Collect + Upload */}
          <div className="shrink-0 border-b border-zinc-800 px-3 py-2.5 flex items-center gap-2.5 text-xs text-zinc-400">
            <button
              onClick={handleCollectClick}
              disabled={checkedIds.size === 0}
              className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium bg-cyan-600 hover:bg-cyan-500 text-white rounded transition disabled:opacity-40 disabled:cursor-not-allowed"
              title="Send selected sessions to MongoDB"
            >
              <Upload className="w-3.5 h-3.5" />
              Collect
            </button>
            <button
              onClick={handleDownloadClick}
              disabled={checkedIds.size === 0}
              className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium bg-emerald-600 hover:bg-emerald-500 text-white rounded transition disabled:opacity-40 disabled:cursor-not-allowed"
              title="Download selected sessions as zip"
            >
              <Download className="w-3.5 h-3.5" />
              Download
            </button>
            <button
              onClick={() => setShowUploadDialog(true)}
              className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium bg-violet-600 hover:bg-violet-500 text-white rounded transition"
              title="Upload conversation files"
            >
              <FileUp className="w-3.5 h-3.5" />
              Upload
            </button>
          </div>

          <SessionList
            sessions={sessions}
            selectedId={selectedSessionId}
            onSelect={setSelectedSessionId}
            checkedIds={checkedIds}
            onCheckedChange={setCheckedIds}
            viewMode={viewMode}
            onViewModeChange={setViewMode}
          />

          {/* Footer: Session count + Pagination */}
          <div className="shrink-0 border-t border-zinc-800 px-3 py-2 flex items-center justify-between text-xs text-zinc-400">
            <span>{sessions.length} sessions</span>
            {viewMode === "time" && (
              <div className="flex items-center gap-1">
                <button
                  onClick={() => setPage(Math.max(0, page - 1))}
                  disabled={page === 0 || loading}
                  className="p-1 hover:bg-zinc-800 disabled:opacity-50 disabled:cursor-not-allowed rounded transition"
                  title="Previous page"
                >
                  <ChevronUp className="w-4 h-4" />
                </button>
                <span className="px-1 text-xs">{page + 1}</span>
                <button
                  onClick={() => setPage(page + 1)}
                  disabled={sessions.length < SESSIONS_PER_PAGE || loading}
                  className="p-1 hover:bg-zinc-800 disabled:opacity-50 disabled:cursor-not-allowed rounded transition"
                  title="Next page"
                >
                  <ChevronDown className="w-4 h-4" />
                </button>
              </div>
            )}
          </div>
        </aside>
      )}

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 bg-zinc-950">
        {/* Header */}
        <header className="flex items-center gap-3 px-6 h-[50px] border-b border-zinc-800 shrink-0 bg-zinc-900/50 backdrop-blur-sm">
          {!sidebarOpen && (
            <button
              onClick={() => setSidebarOpen(true)}
              className="text-zinc-500 hover:text-zinc-300 transition"
              title="Expand sidebar"
            >
              <Menu className="w-4 h-4" />
            </button>
          )}

          {selectedSession ? (
            <>
              <div className="flex-1 min-w-0">
                <p className="text-sm text-zinc-200 truncate font-medium">
                  {selectedSession.first_message || "Session"}
                </p>
                <p className="text-[10px] text-zinc-500 mt-0.5">
                  {selectedSession.project_name}
                  {selectedSession.models?.length > 0 &&
                    ` • ${selectedSession.models.join(", ")}`}
                </p>
              </div>

              <button
                onClick={handleCopyResume}
                className="flex items-center gap-1.5 text-[10px] text-zinc-400 hover:text-zinc-200 border border-zinc-700 hover:border-zinc-600 rounded px-2.5 py-1.5 transition whitespace-nowrap shrink-0"
                title="Copy resume command to clipboard"
              >
                {copied ? (
                  <>
                    <Check className="w-3.5 h-3.5 text-green-400" />
                    Copied!
                  </>
                ) : (
                  <>
                    <Copy className="w-3.5 h-3.5" />
                    Resume
                  </>
                )}
              </button>
            </>
          ) : (
            <div className="text-xs text-zinc-500">
              Select a session to view
            </div>
          )}
        </header>

        {/* Content Area */}
        <div className="flex-1 min-h-0">
          {selectedSessionId ? (
            <SessionView sessionId={selectedSessionId} />
          ) : (
            <div className="flex items-center justify-center h-full">
              <div className="text-center">
                <div className="text-5xl mb-4 opacity-50">✨</div>
                <p className="text-lg font-medium text-zinc-300 mb-1">
                  Welcome to VibeLens
                </p>
                <p className="text-sm text-zinc-500 mb-6">
                  Select a session from the sidebar to explore Claude Code
                  conversations
                </p>
                <div className="text-xs text-zinc-600">
                  <p>{sessions.length} sessions loaded</p>
                  <p>{projects.length} projects available</p>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Dialog overlay */}
      {renderDialog()}

      {/* Upload dialog */}
      {showUploadDialog && (
        <UploadDialog
          onClose={() => setShowUploadDialog(false)}
          onComplete={() => setRefreshKey((k) => k + 1)}
        />
      )}
    </div>
  );
}

content.content:
  1→import {
  2→  ArrowLeft,
  3→  CheckCircle2,
  4→  ChevronRight,
  5→  FileArchive,
  6→  Loader2,
  7→  Monitor,
  8→  Terminal,
  9→  Trash2,
 10→  Upload,
 11→  X,
 12→} from "lucide-react";
 13→import { useCallback, useEffect, useRef, useState } from "react";
 14→import type { AgentType, OSPlatform, UploadCommands, UploadResult } from "../types";
 15→import { CopyButton } from "./copy-button";
 16→
 17→interface UploadDialogProps {
 18→  onClose: () => void;
 19→  onComplete: () => void;
 20→}
 21→
 22→type WizardStep =
 23→  | "select_agent"
 24→  | "select_os"
 25→  | "show_command"
 26→  | "upload_zip"
 27→  | "result";
 28→
 29→const STEP_ORDER: WizardStep[] = [
 30→  "select_agent",
 31→  "select_os",
 32→  "show_command",
 33→  "upload_zip",
 34→  "result",
 35→];
 36→
 37→const STEP_LABELS = ["Agent", "OS", "Command", "Upload", "Done"];
 38→
 39→interface AgentOption {
 40→  type: AgentType;
 41→  label: string;
 42→  description: string;
 43→}
 44→
 45→const AGENT_OPTIONS: AgentOption[] = [
 46→  {
 47→    type: "claude_code",
 48→    label: "Claude Code",
 49→    description: "Anthropic's CLI coding agent",
 50→  },
 51→  {
 52→    type: "codex",
 53→    label: "Codex CLI",
 54→    description: "OpenAI's terminal coding agent",
 55→  },
 56→  {
 57→    type: "gemini",
 58→    label: "Gemini CLI",
 59→    description: "Google's CLI coding agent",
 60→  },
 61→];
 62→
 63→interface OSOption {
 64→  platform: OSPlatform;
 65→  label: string;
 66→}
 67→
 68→const OS_OPTIONS: OSOption[] = [
 69→  { platform: "macos", label: "macOS" },
 70→  { platform: "linux", label: "Linux" },
 71→  { platform: "windows", label: "Windows" },
 72→];
 73→
 74→export function UploadDialog({ onClose, onComplete }: UploadDialogProps) {
 75→  const [step, setStep] = useState<WizardStep>("select_agent");
 76→  const [agentType, setAgentType] = useState<AgentType | null>(null);
 77→  const [osPlatform, setOsPlatform] = useState<OSPlatform | null>(null);
 78→  const [commands, setCommands] = useState<UploadCommands | null>(null);
 79→  const [commandLoading, setCommandLoading] = useState(false);
 80→  const [file, setFile] = useState<File | null>(null);
 81→  const [dragOver, setDragOver] = useState(false);
 82→  const [uploading, setUploading] = useState(false);
 83→  const [result, setResult] = useState<UploadResult | null>(null);
 84→  const inputRef = useRef<HTMLInputElement>(null);
 85→
 86→  const currentIndex = STEP_ORDER.indexOf(step);
 87→  const canGoBack =
 88→    currentIndex > 0 && step !== "result" && !uploading && !commandLoading;
 89→
 90→  const goBack = useCallback(() => {
 91→    const idx = STEP_ORDER.indexOf(step);
 92→    if (idx > 0) setStep(STEP_ORDER[idx - 1]);
 93→  }, [step]);
 94→
 95→  const selectAgent = useCallback((agent: AgentType) => {
 96→    setAgentType(agent);
 97→    setStep("select_os");
 98→  }, []);
 99→
100→  const selectOS = useCallback(
101→    (platform: OSPlatform) => {
102→      setOsPlatform(platform);
103→      setStep("show_command");
104→    },
105→    []
106→  );
107→
108→  useEffect(() => {
109→    if (step !== "show_command" || !agentType || !osPlatform) return;
110→
111→    setCommandLoading(true);
112→    fetch(
113→      `/api/upload/commands?agent_type=${agentType}&os_platform=${osPlatform}`
114→    )
115→      .then((res) => {
116→        if (!res.ok) throw new Error(`HTTP ${res.status}`);
117→        return res.json();
118→      })
119→      .then((data: UploadCommands) => setCommands(data))
120→      .catch(() =>
121→        setCommands({ command: "# Failed to load command", description: "" })
122→      )
123→      .finally(() => setCommandLoading(false));
124→  }, [step, agentType, osPlatform]);
125→
126→  const handleFileDrop = useCallback((e: React.DragEvent) => {
127→    e.preventDefault();
128→    setDragOver(false);
129→    const dropped = e.dataTransfer.files[0];
130→    if (dropped && dropped.name.toLowerCase().endsWith(".zip")) {
131→      setFile(dropped);
132→    }
133→  }, []);
134→
135→  const handleFileSelect = useCallback(
136→    (e: React.ChangeEvent<HTMLInputElement>) => {
137→      const selected = e.target.files?.[0];
138→      if (selected && selected.name.toLowerCase().endsWith(".zip")) {
139→        setFile(selected);
140→      }
141→      e.target.value = "";
142→    },
143→    []
144→  );
145→
146→  const handleUpload = useCallback(async () => {
147→    if (!file || !agentType) return;
148→    setUploading(true);
149→
150→    const formData = new FormData();
151→    formData.append("file", file);
152→    formData.append("agent_type", agentType);
153→
154→    try {
155→      const res = await fetch("/api/upload/zip", {
156→        method: "POST",
157→        body: formData,
158→      });
159→      if (!res.ok) {
160→        const text = await res.text().catch(() => `HTTP ${res.status}`);
161→        setResult({
162→          files_received: 1,
163→          sessions_parsed: 0,
164→          messages_stored: 0,
165→          skipped: 0,
166→          errors: [{ filename: file.name, error: text }],
167→        });
168→      } else {
169→        setResult(await res.json());
170→      }
171→    } catch (err) {
172→      setResult({
173→        files_received: 1,
174→        sessions_parsed: 0,
175→        messages_stored: 0,
176→        skipped: 0,
177→        errors: [{ filename: file.name, error: String(err) }],
178→      });
179→    }
180→    setUploading(false);
181→    setStep("result");
182→  }, [file, agentType]);
183→
184→  const handleDone = useCallback(() => {
185→    if (result && result.sessions_parsed > 0) {
186→      onComplete();
187→    }
188→    onClose();
189→  }, [result, onClose, onComplete]);
190→
191→  const handleDeleteUploaded = useCallback(async () => {
192→    await fetch("/api/upload/sessions", { method: "DELETE" });
193→    onComplete();
194→    onClose();
195→  }, [onComplete, onClose]);
196→
197→  return (
198→    <div className="fixed inset-0 z-50 flex items-center justify-center">
199→      <div
200→        className="absolute inset-0 bg-black/60 backdrop-blur-sm"
201→        onClick={uploading ? undefined : onClose}
202→      />
203→      <div className="relative bg-zinc-900 border border-zinc-700 rounded-lg shadow-2xl w-full max-w-lg mx-4">
204→        {/* Header */}
205→        <div className="flex items-center justify-between px-5 py-4 border-b border-zinc-800">
206→          <div className="flex items-center gap-2">
207→            {canGoBack && (
208→              <button
209→                onClick={goBack}
210→                className="text-zinc-500 hover:text-zinc-300 transition"
211→              >
212→                <ArrowLeft className="w-4 h-4" />
213→              </button>
214→            )}
215→            <h2 className="text-sm font-semibold text-zinc-100">
216→              Upload Conversation Data
217→            </h2>
218→          </div>
219→          <button
220→            onClick={onClose}
221→            disabled={uploading}
222→            className="text-zinc-500 hover:text-zinc-300 transition disabled:opacity-50"
223→          >
224→            <X className="w-4 h-4" />
225→          </button>
226→        </div>
227→
228→        {/* Step indicators */}
229→        <div className="flex items-center justify-center gap-1.5 px-5 py-3 border-b border-zinc-800/50">
230→          {STEP_LABELS.map((label, i) => (
231→            <div key={label} className="flex items-center gap-1.5">
232→              <div
233→                className={`flex items-center gap-1 px-2 py-0.5 rounded-full text-[10px] font-medium transition ${
234→                  i === currentIndex
235→                    ? "bg-violet-600/30 text-violet-300 border border-violet-500/40"
236→                    : i < currentIndex
237→                      ? "bg-zinc-700/50 text-zinc-400"
238→                      : "bg-zinc-800/50 text-zinc-600"
239→                }`}
240→              >
241→                {i < currentIndex ? (
242→                  <CheckCircle2 className="w-2.5 h-2.5" />
243→                ) : (
244→                  <span className="w-2.5 text-center">{i + 1}</span>
245→                )}
246→                {label}
247→              </div>
248→              {i < STEP_LABELS.length - 1 && (
249→                <ChevronRight className="w-3 h-3 text-zinc-700" />
250→              )}
251→            </div>
252→          ))}
253→        </div>
254→
255→        {/* Body */}
256→        <div className="px-5 py-5 min-h-[200px]">
257→          {step === "select_agent" && (
258→            <AgentStep onSelect={selectAgent} />
259→          )}
260→          {step === "select_os" && (
261→            <OSStep onSelect={selectOS} />
262→          )}
263→          {step === "show_command" && (
264→            <CommandStep
265→              commands={commands}
266→              loading={commandLoading}
267→              onNext={() => setStep("upload_zip")}
268→            />
269→          )}
270→          {step === "upload_zip" && (
271→            <ZipUploadStep
272→              file={file}
273→              dragOver={dragOver}
274→              uploading={uploading}
275→              inputRef={inputRef}
276→              onDrop={handleFileDrop}
277→              onDragOver={() => setDragOver(true)}
278→              onDragLeave={() => setDragOver(false)}
279→              onFileSelect={handleFileSelect}
280→              onClickZone={() => inputRef.current?.click()}
281→              onRemoveFile={() => setFile(null)}
282→              onUpload={handleUpload}
283→            />
284→          )}
285→          {step === "result" && result && (
286→            <ResultStep
287→              result={result}
288→              onDone={handleDone}
289→              onDelete={handleDeleteUploaded}
290→            />
291→          )}
292→        </div>
293→      </div>
294→    </div>
295→  );
296→}
297→
298→function AgentStep({ onSelect }: { onSelect: (agent: AgentType) => void }) {
299→  return (
300→    <div className="space-y-3">
301→      <p className="text-sm text-zinc-300">
302→        Which coding agent do you use?
303→      </p>
304→      <div className="grid gap-2">
305→        {AGENT_OPTIONS.map((opt) => (
306→          <button
307→            key={opt.type}
308→            onClick={() => onSelect(opt.type)}
309→            className="flex items-center gap-3 p-3 bg-zinc-800/50 hover:bg-zinc-800 border border-zinc-700/50 hover:border-violet-500/40 rounded-lg transition text-left group"
310→          >
311→            <Terminal className="w-5 h-5 text-zinc-500 group-hover:text-violet-400 transition shrink-0" />
312→            <div>
313→              <p className="text-sm font-medium text-zinc-200">
314→                {opt.label}
315→              </p>
316→              <p className="text-xs text-zinc-500">{opt.description}</p>
317→            </div>
318→            <ChevronRight className="w-4 h-4 text-zinc-600 ml-auto" />
319→          </button>
320→        ))}
321→      </div>
322→    </div>
323→  );
324→}
325→
326→function OSStep({ onSelect }: { onSelect: (platform: OSPlatform) => void }) {
327→  return (
328→    <div className="space-y-3">
329→      <p className="text-sm text-zinc-300">
330→        What's your operating system?
331→      </p>
332→      <div className="grid gap-2">
333→        {OS_OPTIONS.map((opt) => (
334→          <button
335→            key={opt.platform}
336→            onClick={() => onSelect(opt.platform)}
337→            className="flex items-center gap-3 p-3 bg-zinc-800/50 hover:bg-zinc-800 border border-zinc-700/50 hover:border-violet-500/40 rounded-lg transition text-left group"
338→          >
339→            <Monitor className="w-5 h-5 text-zinc-500 group-hover:text-violet-400 transition shrink-0" />
340→            <p className="text-sm font-medium text-zinc-200">{opt.label}</p>
341→            <ChevronRight className="w-4 h-4 text-zinc-600 ml-auto" />
342→          </button>
343→        ))}
344→      </div>
345→    </div>
346→  );
347→}
348→
349→function CommandStep({
350→  commands,
351→  loading,
352→  onNext,
353→}: {
354→  commands: UploadCommands | null;
355→  loading: boolean;
356→  onNext: () => void;
357→}) {
358→  if (loading) {
359→    return (
360→      <div className="flex items-center justify-center py-8">
361→        <Loader2 className="w-5 h-5 text-zinc-500 animate-spin" />
362→      </div>
363→    );
364→  }
365→
366→  return (
367→    <div className="space-y-4">
368→      <p className="text-sm text-zinc-300">
369→        Run this command in your terminal, then upload the generated zip file.
370→      </p>
371→      {commands && (
372→        <>
373→          {commands.description && (
374→            <p className="text-xs text-zinc-500">{commands.description}</p>
375→          )}
376→          <div className="relative">
377→            <pre className="bg-zinc-950 border border-zinc-800 rounded-lg p-3 pr-10 text-xs text-cyan-300 font-mono overflow-x-auto whitespace-pre-wrap break-all">
378→              {commands.command}
379→            </pre>
380→            <div className="absolute top-2 right-2">
381→              <CopyButton text={commands.command} />
382→            </div>
383→          </div>
384→        </>
385→      )}
386→      <div className="flex justify-end">
387→        <button
388→          onClick={onNext}
389→          className="flex items-center gap-1.5 px-3 py-1.5 text-xs text-white bg-violet-600 hover:bg-violet-500 rounded transition"
390→        >
391→          Next
392→          <ChevronRight className="w-3.5 h-3.5" />
393→        </button>
394→      </div>
395→    </div>
396→  );
397→}
398→
399→function ZipUploadStep({
400→  file,
401→  dragOver,
402→  uploading,
403→  inputRef,
404→  onDrop,
405→  onDragOver,
406→  onDragLeave,
407→  onFileSelect,
408→  onClickZone,
409→  onRemoveFile,
410→  onUpload,
411→}: {
412→  file: File | null;
413→  dragOver: boolean;
414→  uploading: boolean;
415→  inputRef: React.RefObject<HTMLInputElement | null>;
416→  onDrop: (e: React.DragEvent) => void;
417→  onDragOver: () => void;
418→  onDragLeave: () => void;
419→  onFileSelect: (e: React.ChangeEvent<HTMLInputElement>) => void;
420→  onClickZone: () => void;
421→  onRemoveFile: () => void;
422→  onUpload: () => void;
423→}) {
424→  return (
425→    <div className="space-y-4">
426→      {/* Drop zone */}
427→      <div
428→        onDragOver={(e) => {
429→          e.preventDefault();
430→          onDragOver();
431→        }}
432→        onDragLeave={onDragLeave}
433→        onDrop={onDrop}
434→        onClick={onClickZone}
435→        className={`flex flex-col items-center justify-center gap-2 p-8 border-2 border-dashed rounded-lg cursor-pointer transition ${
436→          dragOver
437→            ? "border-violet-400 bg-violet-500/10"
438→            : "border-zinc-700 hover:border-zinc-500 bg-zinc-800/30"
439→        }`}
440→      >
441→        <FileArchive
442→          className={`w-8 h-8 ${dragOver ? "text-violet-400" : "text-zinc-500"}`}
443→        />
444→        <p className="text-sm text-zinc-300">Drop your .zip file here</p>
445→        <p className="text-xs text-zinc-500">
446→          Or click to browse
447→        </p>
448→        <input
449→          ref={inputRef}
450→          type="file"
451→          accept=".zip"
452→          className="hidden"
453→          onChange={onFileSelect}
454→        />
455→      </div>
456→
