 22→  type: "text" | "thinking" | "tool_use" | "tool_result";
 23→  text?: string;
 24→  thinking?: string;
 25→  id?: string;
 26→  name?: string;
 27→  input?: unknown;
 28→  tool_use_id?: string;
 29→  content?: string | ContentBlock[];
 30→  is_error?: boolean;
 31→}
 32→
